import torch
import torch.nn as nn
import torch.optim as optim
from torch.utils.data import DataLoader, Dataset
import requests
from pathlib import Path
import os

class CustomDataset(Dataset):
    def __init__(self, data, labels):
        self.data = data
        self.labels = labels
    
    def __len__(self):
        return len(self.data)
    
    def __getitem__(self, idx):
        return self.data[idx], self.labels[idx]

def download_model_from_url(url, save_path):
    """Download model from URL and save it locally"""
    response = requests.get(url)
    response.raise_for_status()
    
    with open(save_path, 'wb') as f:
        f.write(response.content)
    
    return save_path

def load_model_from_url(url, model_class, device='cpu'):
    """Load model from URL"""
    # Create temporary file
    temp_path = Path("temp_model.pth")
    
    # Download model
    download_model_from_url(url, temp_path)
    
    # Load model
    model = model_class()
    checkpoint = torch.load(temp_path, map_location=device)
    model.load_state_dict(checkpoint)
    
    # Remove temporary file
    temp_path.unlink()
    
    return model

def fine_tune_model(model, train_loader, val_loader, num_epochs=5, learning_rate=1e-4, device='cpu'):
    """Fine-tune the model on custom dataset"""
    model = model.to(device)
    
    # Define loss and optimizer
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam(model.parameters(), lr=learning_rate)
    
    # Training loop
    for epoch in range(num_epochs):
        model.train()
        running_loss = 0.0
        
        for inputs, labels in train_loader:
            inputs, labels = inputs.to(device), labels.to(device)
            
            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()
            
            running_loss += loss.item()
        
        # Validation
        model.eval()
        correct = 0
        total = 0
        with torch.no_grad():
            for inputs, labels in val_loader:
                inputs, labels = inputs.to(device), labels.to(device)
                outputs = model(inputs)
                _, predicted = torch.max(outputs, 1)
                total += labels.size(0)
                correct += (predicted == labels).sum().item()
        
        print(f'Epoch [{epoch+1}/{num_epochs}], Loss: {running_loss/len(train_loader):.4f}, '
              f'Val Accuracy: {100*correct/total:.2f}%')
    
    return model

